import{_ as a,o as r,c as e,a0 as o}from"./chunks/framework.D-nrWduk.js";const c=JSON.parse('{"title":"关于 - AI工具导航","description":"了解AI工具导航网站的收录标准、目标和联系方式。我们致力于为用户提供最实用的AI工具和下载工具导航服务。","frontmatter":{"layout":"page","title":"关于 - AI工具导航","description":"了解AI工具导航网站的收录标准、目标和联系方式。我们致力于为用户提供最实用的AI工具和下载工具导航服务。","robots":"index, follow"},"headers":[],"relativePath":"about.md","filePath":"about.md","lastUpdated":1775813740000}'),l={name:"about.md"};function i(d,t,n,s,h,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h2 id="关于ai工具导航" tabindex="-1">关于AI工具导航 <a class="header-anchor" href="#关于ai工具导航" aria-label="Permalink to &quot;关于AI工具导航&quot;">​</a></h2><p><strong>AI工具导航</strong>是一个专注于聚合最实用AI工具与高频下载工具的导航网站，致力于帮助用户快速找到高质量的生产力工具。</p><h2 id="我们的目标" tabindex="-1">我们的目标 <a class="header-anchor" href="#我们的目标" aria-label="Permalink to &quot;我们的目标&quot;">​</a></h2><ul><li>🎯 <strong>精选高质量工具</strong>：经过实际使用验证，节省筛选时间</li><li>🆓 <strong>推荐免费/开源替代方案</strong>：帮助用户降低成本</li><li>📚 <strong>提供工具使用技巧</strong>：让每个工具发挥最大价值</li><li>🔄 <strong>持续更新迭代</strong>：跟踪AI领域最新动态，及时更新工具列表</li></ul><h2 id="收录标准" tabindex="-1">收录标准 <a class="header-anchor" href="#收录标准" aria-label="Permalink to &quot;收录标准&quot;">​</a></h2><p>我们坚持以下标准进行工具收录：</p><ol><li><strong>实用性</strong> - 经过实际使用验证，真正能提升效率</li><li><strong>易用性</strong> - 上手简单，无需复杂配置或技术背景</li><li><strong>稳定性</strong> - 服务稳定，更新及时，有持续维护</li><li><strong>安全性</strong> - 无恶意软件，无隐私风险</li><li><strong>合法性</strong> - 遵守相关法律法规，不收录违规工具</li></ol><h2 id="工具分类" tabindex="-1">工具分类 <a class="header-anchor" href="#工具分类" aria-label="Permalink to &quot;工具分类&quot;">​</a></h2><table tabindex="0"><thead><tr><th>分类</th><th>说明</th></tr></thead><tbody><tr><td>💬 AI对话</td><td>ChatGPT、Claude、通义千问等对话AI</td></tr><tr><td>🎨 AI图像</td><td>Midjourney、Stable Diffusion等绘画工具</td></tr><tr><td>🎬 AI视频</td><td>Sora、Runway、Pika等视频生成工具</td></tr><tr><td>✍️ AI写作</td><td>Notion AI、秘塔写作猫等AI写作助手</td></tr><tr><td>🎵 AI音频</td><td>ElevenLabs、讯飞听见等语音处理工具</td></tr><tr><td>📊 AI办公</td><td>Gamma、Beautiful.ai等AI办公工具</td></tr><tr><td>🌐 浏览器</td><td>Chrome、Firefox等主流浏览器</td></tr><tr><td>📥 下载工具</td><td>IDM、Motrix等下载管理器</td></tr><tr><td>🛠️ 系统工具</td><td>Potplayer、7-Zip等系统工具</td></tr><tr><td>💻 开发工具</td><td>VS Code、Git、Docker等开发必备</td></tr></tbody></table><h2 id="免责说明" tabindex="-1">免责说明 <a class="header-anchor" href="#免责说明" aria-label="Permalink to &quot;免责说明&quot;">​</a></h2><ul><li>本网站仅提供工具导航链接，不存储、不托管任何工具</li><li>所有工具版权归各自开发者或运营方所有</li><li>请遵守各平台的使用协议和相关法律法规</li><li>因使用第三方工具产生的任何问题，与本网站无关</li></ul><h2 id="联系我们" tabindex="-1">联系我们 <a class="header-anchor" href="#联系我们" aria-label="Permalink to &quot;联系我们&quot;">​</a></h2><p>欢迎推荐优质工具或反馈失效链接：</p><ul><li>在 <a href="https://github.com/jm6-lang/tool-nav/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 提交收录建议</li><li>关注我们的 <a href="https://github.com/jm6-lang/tool-nav" target="_blank" rel="noreferrer">GitHub 仓库</a> 获取最新更新</li></ul>',14)])])}const g=a(l,[["render",i]]);export{c as __pageData,g as default};
